function ProductList() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // BAD: refetches every time the component mounts
    // No caching, no deduplication, no stale-while-revalidate
    fetch("/api/products")
      .then((r) => r.json())
      .then(setProducts)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <Spinner />;
  return <ul>{products.map((p) => <li key={p.id}>{p.name}</li>)}</ul>;
}

import { useQuery } from "@tanstack/react-query";

function ProductList() {
  const { data: products, isLoading, error } = useQuery({
    queryKey: ["products"],
    queryFn: () => fetch("/api/products").then((r) => r.json()),
    staleTime: 5 * 60 * 1000, // Consider data fresh for 5 minutes
  });

  if (isLoading) return <Spinner />;
  if (error) return <ErrorMessage error={error} />;
  return <ul>{products.map((p) => <li key={p.id}>{p.name}</li>)}</ul>;
}

// Benefits:
// - Cached: navigating away and back shows data instantly
// - Deduplicated: 10 components requesting the same key = 1 fetch
// - Background refresh: stale data is shown while fresh data loads
// - Automatic retries on failure
// - Garbage collected when no components are subscribed
